// 西游记 81章数据 - 轻量版
const chapters = [
    {id:1,title:"第一回",subtitle:"灵根孕育源流出",img:"🐒",content:"<p>很久很久以前，天地还没有分开，整个世界就像一个大鸡蛋，混沌一片。</p><p>在这个大鸡蛋里，孕育着一个巨大的神灵——盘古。他睡了一万八千年后醒来，用斧头劈开天地。</p><p>天升为上，地沉为下。盘古死后，身体变成日月星辰、江河湖海，世界就这样形成了。</p><p>世界分四大部洲：东胜神州、西牛贺洲、南瞻部洲、北俱芦洲。东胜神州有个傲来国，海边有座花果山。</p><p>花果山顶有块仙石，吸收天地灵气、日月精华，孕育出一只石猴！石猴出生时眼睛射出金光，直冲云霄！</p><p>玉帝想派人查看，太白金星说：这是天地精华所生，吃了凡间食物就会没事。</p><p>石猴在花果山和猴子们快乐生活。有一天，天气炎热，猴子们发现瀑布后有水帘洞。</p><p>石猴跳过瀑布，进入洞中，被众猴拜为美猴王。</p><p>但美猴王担心生老病死。一只通背猿猴说：佛、仙、神可以长生不老。</p><p>美猴王决定出海寻访神仙，学长生不老之术...</p>"},
    {id:2,title:"第二回",subtitle:"悟彻菩提真妙理",img:"🏔️",content:"<p>美猴王离别花果山，驾木筏漂洋过海，历尽艰辛寻找神仙。</p><p>终于来到西牛贺洲的灵台方寸山，遇到砍柴樵夫，得知斜月三星洞有菩提祖师。</p><p>美猴王见到菩提祖师，跪拜请求收为徒弟。祖师赐名孙悟空。</p><p>孙悟空在洞中学习读书写字，几年后有一天，祖师在讲坛上讲道。</p><p>徒弟们展示本领，轮到悟空他说什么都不会。祖师让他三更时去找自己。</p><p>三更时悟空从后门进入，祖师传授他长生不老之术——大品天仙诀！</p><p>悟空学会后，祖师又教他七十二变和筋斗云。七十二变能变万物，筋斗云一翻十万八千里！</p><p>学成本领后，祖师让悟空下山：不可仗技惹事，否则收回本领！</p><p>悟空拜别师父，驾筋斗云回花果山...</p>"},
    {id:3,title:"第三回",subtitle:"大闹天宫",img:"⚡",content:"<p>孙悟空回到花果山，猴子们欢呼迎接。悟空有了金箍棒，更加威风。</p><p>他想去天宫展示本领，一个筋斗翻到南天门。守门天兵拦住他：哪来的猴子？</p><p>悟空说：我是齐天大圣！天兵去禀报玉帝。</p><p>太白金星建议招安，封悟空为弼马温。悟空不知道是养马的官，高兴上任。</p><p>后来知道弼马温是末等小官，悟空大怒：让我养马？反下天宫！</p><p>玉帝派托塔李天王捉拿。巨灵神、哪吒三太子都不是对手。</p><p>太白金星又建议封悟空为齐天大圣，有府邸无实权。悟空满意。</p><p>悟空每天无所事事，听说蟠桃园蟠桃好吃，跑去偷吃。</p><p>这可闯下大祸...</p>"},
    {id:4,title:"第四回",subtitle:"五行山下定心猿",img:"🏔️",content:"<p>孙悟空大闹天宫，偷吃蟠桃、仙酒，闯入太上老君八卦炉。</p><p>炼了四十九天没死，反而炼成火眼金睛！悟空跳出八卦炉打向凌霄宝殿。</p><p>玉帝请如来佛祖。佛祖和悟空打赌：飞出他手掌心就让位。</p><p>悟空一个筋斗翻到天边柱子，写下'齐天大圣到此一游'，以为飞出。</p><p>回来发现仍在如来掌心，写的字在佛祖手指上！</p><p>佛祖翻手一压，五行山压住悟空！贴上符咒，五百年无法逃脱。</p><p>五百年后，观音菩萨告诉悟空：等取经人唐僧来救你。</p><p>终于有一天，唐僧路过五行山...</p>"},
    {id:5,title:"第五回",subtitle:"观音禅院救火僧",img:"🛕",content:"<p>唐僧救出孙悟空，师徒二人继续西行。来到观音禅院借宿。</p><p>方丈金池长老看到唐僧的锦斓袈裟起了贪心，想据为己有。</p><p>晚上让徒弟黑熊精偷走袈裟。悟空用火眼金睛发现是黑熊精所为。</p><p>悟空飞到黑风山讨要，黑熊精躲进洞不出来。</p><p>观音菩萨帮助，变成美女进洞，现真身收服黑熊精为守山大神。</p><p>师徒继续前进，来到高老庄...</p>"},
    {id:6,title:"第六回",subtitle:"猪八戒拜师",img:"🐷",content:"<p>高老庄高太公求救：女儿被妖怪抓走。悟空变成高小姐引出妖怪。</p><p>妖怪现原形是猪八戒——天蓬元帅！因调戏嫦娥被贬下凡错投猪胎。</p><p>观音菩萨点化，八戒愿意保护取经，取名猪八戒。</p><p>师徒三人继续，来到流沙河...</p>"},
    {id:7,title:"第七回",subtitle:"流沙河收沙僧",img:"🌊",content:"<p>流沙河波浪汹涌，妖怪冲出——卷帘大将沙僧！</p><p>沙僧原是玉帝卷帘大将，失手打碎琉璃盏被贬，在流沙河吃人。</p><p>观音菩萨收服，取名沙悟净。脖子骷髅做成船，师徒过河。</p><p>取经团队凑齐：唐僧、悟空、八戒、沙僧、白龙马！</p>"},
    {id:8,title:"第八回",subtitle:"四圣试禅心",img:"☁️",content:"<p>师徒四人继续西行，天色晚了看到一座庄院。</p><p>寡妇要嫁三女儿给师徒四人。唐僧拒绝，八戒动了心。</p><p>原来是观音、普贤、文殊、黎山老母试禅心！</p><p>八戒被教训，师徒继续取经...</p>"},
    {id:9,title:"第九回",subtitle:"三打白骨精",img:"👻",content:"<p>白虎岭上，悟空去化斋。白骨精变成姑娘送饭。</p><p>悟空回来用火眼金睛看出是妖怪，一棒打死。</p><p>唐僧责怪悟空杀人。继续走，又来老婆婆、老头。</p><p>悟空都打死，现出白骨。唐僧赶走悟空！</p><p>悟空含泪离开...</p>"},
    {id:10,title:"第十回",subtitle:"真假美猴王",img:"🐒",content:"<p>悟空走后，六耳猕猴假冒悟空，抢走行李。</p><p>真假悟空打到南海、天宫、地府，都分不出。</p><p>如来佛祖指出六耳猕猴，真悟空打死。</p><p>师徒重归于好，继续取经...</p>"},
    {id:11,title:"第十一回",subtitle:"红孩儿",img:"🔥",content:"<p>师徒来到火云洞。红孩儿抓走唐僧！</p><p>红孩儿是牛魔王儿子，会喷三昧真火。悟空被打败。</p><p>请观音菩萨，收红孩儿为善财童子。</p>"},
    {id:12,title:"第十二回",subtitle:"三调芭蕉扇",img:"🔥",content:"<p>火焰山火大无法过。悟空找铁扇公主借芭蕉扇。</p><p>铁扇公主是牛魔王妻子，不借。第一次被扇飞。</p><p>悟空变小虫进肚子，拿到假扇。</p><p>找到真的芭蕉扇，扇灭大火。</p>"},
    {id:13,title:"第十三回",subtitle:"女儿国",img:"👩",content:"<p>女儿国没有男人，都是女人。国王要嫁唐僧。</p><p>唐僧假意答应，悟空设计逃跑。继续西行。</p>"},
    {id:14,title:"第十四回",subtitle:"小雷音寺",img:"🏛️",content:"<p>小雷音寺妖怪黄眉大王，有人种袋金铙。</p><p>师徒被抓住。如来佛祖收服妖怪。</p>"},
    {id:15,title:"第十五回",subtitle:"盘丝洞",img:"🕷️",content:"<p>盘丝洞七只蜘蛛精抓走唐僧。</p><p>悟空请毗蓝婆菩萨收服蜘蛛精。</p>"},
    {id:16,title:"第十六回",subtitle:"狮驼岭",img:"🦁",content:"<p>狮驼岭三大王：青狮、白象、大鹏。</p><p>本领高强，抓住师徒。如来亲自收服。</p>"},
    {id:17,title:"第十七回",subtitle:"比丘国",img:"🦌",content:"<p>比丘国国王被白鹿精迷惑，要小儿心肝做药引。</p><p>悟空揭露，南极老人收服白鹿。</p>"},
    {id:18,title:"第十八回",subtitle:"无底洞",img:"🐀",content:"<p>无底洞老鼠精抓走唐僧逼婚。</p><p>老鼠精是托塔天王干女儿。李天王收服。</p>"},
    {id:19,title:"第十九回",subtitle:"天竺国",img:"🐰",content:"<p>天竺国公主抛绣球招亲唐僧。</p><p>玉兔精假扮。嫦娥收服玉兔。</p>"},
    {id:20,title:"第二十回",subtitle:"取得真经",img:"📜",content:"<p>师徒终于到达灵山！</p><p>如来传三藏真经。</p><p>阿傩伽叶索贿，给无字经。</p><p>发现后再换有字经。</p><p>返回大唐，修成正果！</p>"}
];

let current = 0;

function init() {
    renderList();
    document.getElementById('loading').classList.add('hidden');
}

function renderList() {
    const list = document.getElementById('chapterList');
    chapters.forEach((ch,i) => {
        const li = document.createElement('li');
        li.innerHTML = `<b>${i+1}.</b> ${ch.title} ${ch.subtitle}`;
        li.onclick = () => goChapter(i);
        list.appendChild(li);
    });
}

function showCover() {
    document.getElementById('cover').style.display = 'block';
    document.getElementById('chapterContent').innerHTML = '';
    document.getElementById('nav').style.display = 'none';
    toggleSidebar();
    current = 0;
    updateNav();
}

function startReading() {
    current = 0;
    showChapter(0);
}

function goChapter(i) {
    showChapter(i);
    toggleSidebar();
}

function showChapter(i) {
    if(i<0||i>=chapters.length) return;
    current = i;
    const ch = chapters[i];
    document.getElementById('cover').style.display = 'none';
    const html = `<div class="chapter active">
        <h2>${ch.title} ${ch.subtitle}</h2>
        <div class="chapter-img">${ch.img}</div>
        <div class="story">${ch.content}</div>
    </div>`;
    document.getElementById('chapterContent').innerHTML = html;
    document.getElementById('nav').style.display = 'flex';
    updateNav();
    window.scrollTo(0,0);
}

function prevChapter() { showChapter(current-1); }
function nextChapter() { showChapter(current+1); }

function updateNav() {
    document.getElementById('prevBtn').disabled = current===0;
    document.getElementById('nextBtn').disabled = current===chapters.length-1;
    document.getElementById('indicator').textContent = `${current+1}/${chapters.length}`;
}

function toggleSidebar() {
    document.getElementById('sidebar').classList.toggle('active');
    document.querySelector('.overlay').classList.toggle('active');
}

document.addEventListener('DOMContentLoaded',init);
